class MinHeap {
private:
    std::vector<int> heap;
    void heapifyUp(int index) {
        if (index && heap[parent(index)] > heap[index]) {
            std::swap(heap[index], heap[parent(index)]);
            heapifyUp(parent(index));
        }
    }
    void heapifyDown(int index) {
        int left = leftChild(index);
        int right = rightChild(index);
        int smallestChild = index;
        if (left < size() && heap[left] < heap[smallestChild])
            smallestChild = left;
        if (right < size() && heap[right] < heap[smallestChild])
            smallestChild = right;
        if (smallestChild != index) {
            std::swap(heap[index], heap[smallestChild]);
            heapifyDown(smallestChild);
        }
    }
    int parent(int index) { return (index - 1) / 2; }
    int leftChild(int index) { return (2 * index + 1); }
    int rightChild(int index) { return (2 * index + 2); }
public:
    int size() { return heap.size(); }
    bool isEmpty() { return size() == 0; }
    void insert(int key) {
        heap.push_back(key);
        int index = size() - 1;
        heapifyUp(index);
    }
    int getMin() { return isEmpty() ? -1 : heap[0]; }
    int extractMin() {
        if (size() == 0) return -1;
        if (size() == 1) {
            int root = heap[0];
            heap.pop_back();
            return root;
        }
        int root = heap[0];
        heap[0] = heap.back();
        heap.pop_back();
        heapifyDown(0);
        return root;
    }
};

